import{_ as e,o as t,c as i,a}from"./app.014522ac.js";const f=JSON.parse('{"title":"Yoahtl v. 14uu, Oct 2017","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/yoahtl_v_14uu_oct_2017.md","lastUpdated":1665949328000}'),n={name:"government/court-cases-precedents/yoahtl_v_14uu_oct_2017.md"},r=a('<h1 id="yoahtl-v-14uu-oct-2017" tabindex="-1">Yoahtl v. 14uu, Oct 2017 <a class="header-anchor" href="#yoahtl-v-14uu-oct-2017" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: Klasikrok</p><p><strong>Date</strong>: 20th October 2017</p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><ol><li>Construction of an illegal hazardous structure leading to inescapable harm (aka a &#39;deathtrap&#39;)</li><li>Two counts of murder via a deathtrap (DevFTW and Crustifer)</li></ol><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><ol><li><p>Not guilty on reason of other people&#39;s meddling with the grinder creating the hazardous situation, not 14uu himself.</p></li><li><p>Not guilty on reason of DevFTW and Crustifer being the ones who interfered with the grinder.</p></li></ol><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><p>14uu alleges that DevFTW and Crustifer created the deathtrap by meddling with the spider grinder (which was surrounded by SRO so anybody who fell in would drown) and that he is not guilty of negligent behavior with the construction of the apparatus since they were the ones who interfered. He also claims that his grinder is private.</p></li><li><p>TheOrangeWizard says that &#39;if the public can access it without placing or breaking blocks, you cannot forbid them from entering the area&#39;</p></li><li><p>&#39;it needed breaking blocks until dev griefed so he fell on his own deathtrap both would have the itens gotten to a chest thru a hopper but as dev grief my skele grinder i unassembked it and a gain if he fell on it it would be his own deathtrap&#39; -14uu (14 implicitly admits that DevFTW and Crustifer&#39;s lost items were indeed lost and by his interference by removing the hopper and chest, but that it was their own fault).</p></li><li><p>Feathercrown is brought in and denies TheOrangeWizard&#39;s definition of 14uu&#39;s grinder as public, stating that &#39;Orange thats not right. Unless the grinder was public before.&#39;</p></li><li><p>14uu says that the skeleton grinder in question was made before the council passed laws regarding spawners as public property and that both of 14uu&#39;s grinders were private both before and after the decision. (The decision in question is Council 5.4 Unimproved spawners are considered public property and breaking them without government approval is considered a crime. Note that the language &#39;spawner&#39; is referring to the specific block found in a pre-generated dungeon that spawns hostile mobs. However, there is some ambiguity about constructing grinders around them being under the jurisdiction of the government via the Extinction Rule and so the government is allowed to set conditions on people claiming spawners as their private property. 14uu is saying that he was given an allowance under the Extinction Rule to run his grinder as private regardless of who could access it.)</p></li><li><p>TheOrangeWizard states that a private grinder is fine, but if it kills players then the owner is responsible for losses and damages</p></li><li><p>14uu says it&#39;s not negligence on his part if people break into his grinder and then die because they broke into it of their own volition</p></li><li><p>WackyAki interjects and demands screenshots of the grinder and a list of what DevFTW and Crustifer are claiming as losses</p></li><li><p>bgbba specifies that DevFTW lost a Prot IV chestplate, while Crustifer&#39;s losses are unspecified at the moment</p></li><li><p>Aki says the chestplate should be valued at 40 diamonds</p></li><li><p>TheOrangeWizard testifies that on personal examination he believes that 14uu built a grinder that was fundamentally unsafe and provides screenshots here: The grinder, the death hole itself</p></li><li><p>Orange testifies that DevFTW could have just walked in</p></li><li><p>14uu alleges again that DevFTW griefed the grinder, causing his own death</p></li><li><p>WackyAki says that it appears DevFTW caused his own death</p></li><li><p>Charge of 14uu constructing the deathtrap is dropped</p></li><li><p>WackyAki alleges that 14uu is not at fault for DevFTW&#39;s death</p></li><li><p>bgbba alleges the grinder was indeed public and owes DevFTW&#39;s reps for having a poorly constructed grinder</p></li><li><p>WackyAki says that it&#39;s the city&#39;s job to ensure good maintenance of things by pressuring citizens</p></li><li><p>bgbba says that the government tried and that 14uu refused</p></li><li><p>Ensuing discussion goes nowhere</p></li><li><p>14uu is offered a compromise &quot;14, I propose a compromise: Since Dev griefed the grinder to start with, it&#39;s his own fault for falling in and dying. However, you have failed to adequately improve the grinder. Would you remove the IRO and allow Dev to make the grinder fully functional and not dangerous, but you can keep owning it?&quot; -bgbba</p></li><li><p>14uu claims it&#39;s not fair</p></li><li><p>14uu takes the compromise</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><p>14uu gives DevFTW access to improve the grinder, but retains ownership.</p>',11),s=[r];function o(l,h,d,u,p,c){return t(),i("div",null,s)}const b=e(n,[["render",o]]);export{f as __pageData,b as default};
